const error = $input.first().json;

const errorReport = {
  workflow_name: error.workflow?.name || 'Business Email Management - Outlook',
  workflow_id: error.workflow?.id || 'unknown',
  node_name: error.execution?.error?.node?.name || 'unknown',
  error_message: error.execution?.error?.message || 'Unknown error',
  timestamp: new Date().toISOString(),
  execution_id: error.execution?.id || 'unknown',
  severity: 'high',
  alert_subject: `[ALERT] Email Workflow Error: ${error.execution?.error?.node?.name || 'unknown node'}`,
  alert_body: `Workflow: Business Email Management - Outlook\nNode: ${error.execution?.error?.node?.name || 'unknown'}\nError: ${error.execution?.error?.message || 'Unknown error'}\nTime: ${new Date().toISOString()}\nExecution ID: ${error.execution?.id || 'unknown'}\n\nPlease investigate immediately.`
};

return [{ json: errorReport }];
